// Flutter imports:
import 'package:flutter/material.dart';

// Package imports:
import 'package:collection/collection.dart';
import 'package:gap/gap.dart';
import 'package:hooks_riverpod/hooks_riverpod.dart';

// Project imports:
import 'package:baseball_detector_flutter/data/models/ai_coach/pitch_zones.dart';
import 'package:baseball_detector_flutter/gen/assets.gen.dart';
import 'package:baseball_detector_flutter/l10n/l10n_ext.dart';
import 'package:baseball_detector_flutter/views/pages/home/sessions/session_details/ai_coach_report/components/expansion_tile_card.dart';
import 'package:baseball_detector_flutter/views/pages/home/sessions/session_details/hooks/use_pitch_type_map.dart';

/// 推奨投球コース（3x3）のエクスパンションタイル
/// 表示内容は `AiCoachPitchZonesPage` と同様のレイアウトに合わせる。
class PitchZonesExpansionTile extends HookConsumerWidget {
  const PitchZonesExpansionTile({
    super.key,
    required this.items,
    this.titleStyle,
    this.subtitleStyle,
  });

  final List<PitchZoneByPitch> items;
  final TextStyle? titleStyle;
  final TextStyle? subtitleStyle;

  @override
  Widget build(BuildContext context, WidgetRef ref) {
    final theme = Theme.of(context);
    final scheme = theme.colorScheme;
    final l10n = context.l10n;
    final getPitchTypeColor = usePitchTypeColor();
    final translatePitchType = useTranslatePitchType();
    final effectiveTitleStyle = titleStyle ??
        theme.textTheme.titleMedium?.copyWith(
          fontWeight: FontWeight.w600,
          color: scheme.onSurface,
        );
    final effectiveSubtitleStyle = subtitleStyle ??
        theme.textTheme.bodySmall?.copyWith(
          color: scheme.onSurfaceVariant,
        );

    Widget block(int i, PitchZoneByPitch pitch) {
      final pitchTypeKey = pitch.pitchType.pitchType;
      final label = translatePitchType(pitchTypeKey);
      return Column(
        crossAxisAlignment: CrossAxisAlignment.stretch,
        children: [
          Container(
            decoration: BoxDecoration(
              color: getPitchTypeColor(pitchTypeKey),
              borderRadius:
                  const BorderRadius.vertical(top: Radius.circular(4)),
            ),
            padding: const EdgeInsets.symmetric(horizontal: 16, vertical: 12),
            child: Text(
              label,
              style: theme.textTheme.titleSmall?.copyWith(
                color: Colors.white,
                fontWeight: FontWeight.w600,
              ),
            ),
          ),
          Container(
            decoration: BoxDecoration(
              color: const Color(0xFFFAFBFC),
              borderRadius:
                  const BorderRadius.vertical(bottom: Radius.circular(8)),
              border: Border.all(color: const Color(0xFFE5E7EB)),
            ),
            padding: const EdgeInsets.all(16),
            child: Row(
              mainAxisAlignment: MainAxisAlignment.spaceBetween,
              crossAxisAlignment: CrossAxisAlignment.start,
              children: [
                _ZonePanel(
                  title: l10n.ai_coach_report__vs_right_batter,
                  recommended: pitch.vsRight.recommendedZones,
                  descriptions: pitch.vsRight.notes,
                ),
                _ZonePanel(
                  title: l10n.ai_coach_report__vs_left_batter,
                  recommended: pitch.vsLeft.recommendedZones,
                  descriptions: pitch.vsLeft.notes,
                ),
              ],
            ),
          ),
        ],
      );
    }

    return ExpansionTileCard(
      titleBuilder: (icon) => Row(
        mainAxisAlignment: MainAxisAlignment.spaceBetween,
        children: [
          Column(
            crossAxisAlignment: CrossAxisAlignment.start,
            children: [
              Text(
                l10n.ai_coach_report__pitch_zones_title,
                style: effectiveTitleStyle,
              ),
              const Gap(4),
              Text(
                l10n.ai_coach_report__pitch_zones_subtitle(items.length),
                style: effectiveSubtitleStyle,
              ),
            ],
          ),
          icon,
        ],
      ),
      children: items.mapIndexed((i, e) => block(i, e)).toList(),
    );
  }
}

class _ZonePanel extends StatelessWidget {
  const _ZonePanel({
    required this.title,
    required this.recommended,
    required this.descriptions,
  });

  static const _defaultBackgroundColor = Colors.white;
  static const _borderColor = Color(0xFFBDBDBD);

  final String title;
  final List<int> recommended; // 1..9
  final List<String> descriptions;

  @override
  Widget build(BuildContext context) {
    final theme = Theme.of(context);
    final scheme = theme.colorScheme;
    final textTheme = theme.textTheme;

    Widget zoneCell(int n) {
      final isRec = recommended.contains(n);
      final backgroundColor = isRec ? Colors.yellow : _defaultBackgroundColor;
      final numberStyle = textTheme.bodySmall?.copyWith(
            fontWeight: FontWeight.w700,
            color: Colors.black87,
          ) ??
          const TextStyle(
            fontWeight: FontWeight.w700,
            color: Colors.black87,
            fontSize: 12,
          );
      return Container(
        alignment: Alignment.center,
        decoration: BoxDecoration(
          color: backgroundColor,
          border: Border.all(color: _borderColor),
        ),
        child: Stack(
          alignment: Alignment.center,
          children: [
            Text('$n', style: numberStyle),
            if (isRec)
              Align(
                child: Padding(
                  padding: const EdgeInsets.all(2.0),
                  child: Text(
                    '◎',
                    style: TextStyle(
                      color: scheme.error,
                      fontSize: 20,
                      fontWeight: FontWeight.w800,
                    ),
                  ),
                ),
              ),
          ],
        ),
      );
    }

    return Column(
      crossAxisAlignment: CrossAxisAlignment.center,
      children: [
        Text(
          title,
          style: TextStyle(
            color: Colors.black87,
            fontWeight: FontWeight.w700,
          ),
        ),
        const Gap(8),
        SizedBox(
          width: 120,
          height: 120,
          child: GridView.count(
            crossAxisCount: 3,
            mainAxisSpacing: 0,
            crossAxisSpacing: 0,
            physics: const NeverScrollableScrollPhysics(),
            shrinkWrap: true,
            children: [for (var n = 1; n <= 9; n++) zoneCell(n)],
          ),
        ),
        const Gap(12),
        Assets.images.icHomePlate.svg(width: 88),
        const Gap(12),
        Container(
          padding: const EdgeInsets.all(8),
          width: 160,
          decoration: BoxDecoration(
            borderRadius: BorderRadius.circular(6),
            border: Border.all(
              color: scheme.outlineVariant.withValues(alpha: 0.3),
            ),
          ),
          child: Column(
            crossAxisAlignment: CrossAxisAlignment.start,
            children: [
              for (final d in descriptions)
                Padding(
                  padding: const EdgeInsets.symmetric(vertical: 2),
                  child: Text(
                    d,
                    style: TextStyle(
                      color: Colors.black87,
                      fontSize: 12,
                    ),
                  ),
                ),
            ],
          ),
        ),
      ],
    );
  }
}

